exercises.solution_code:
#include <cstdint>
#include <cstddef>
#include <iostream>

int main()
{
    int32_t a{}, b{};
    std::cin >> a >> b;

    uint8_t  r8  = static_cast<uint8_t> (a + b);
    uint16_t r16 = static_cast<uint16_t>(a + b);
    uint32_t r32 = static_cast<uint32_t>(a + b);

    bool overflow8  { static_cast<uint32_t>(r8)  != r32 };
    bool overflow16 { static_cast<uint32_t>(r16) != r32 };

    std::cout << "uint8_t  result: " << static_cast<uint32_t>(r8)  << '\n';
    std::cout << "uint16_t result: " << static_cast<uint32_t>(r16) << '\n';
    std::cout << "uint32_t result: " << r32 << '\n';
    std::cout << std::boolalpha;
    std::cout << "uint8_t  overflow: " << overflow8  << '\n';
    std::cout << "uint16_t overflow: " << overflow16 << '\n';

    return 0;
}
